package dev.conjure.gen.assets;

import dev.conjure.gen.DynamicPackManager;

import java.io.IOException;

/**
 * Writes entity-related dynamic assets to the Conjure runtime resource pack.
 *
 * <p>Currently handles only the skin texture.  The geo model and animation files are
 * static (bundled in the mod jar under {@code assets/conjure/geo/} and
 * {@code assets/conjure/animations/}) and never generated — only the per-slot skin
 * PNG is generated by AI and written here.
 *
 * <p>Texture path convention:
 * <pre>
 *   assets/conjure/textures/entity/entity_slot_{N}.png
 * </pre>
 * The corresponding {@link dev.conjure.content.SlotDefinition#texturePath} stored in the
 * registry is {@code "conjure:entity/entity_slot_{N}"} (no {@code textures/} prefix, no
 * {@code .png} suffix — standard MC resource-location format).
 */
public final class EntityAssets {

    /**
     * Writes the AI-generated skin PNG to the dynamic resource pack so that
     * {@link dev.conjure.client.ConjureMobModel} can resolve it via
     * {@code SlotDefinition#texturePath}.
     *
     * @param slotIndex the global entity slot index (0-based)
     * @param argb      16×16 (or larger) ARGB pixel grid {@code [y][x]}
     * @throws IOException if the file cannot be written
     */
    public static void writeSkinTexture(int slotIndex, int[][] argb) throws IOException {
        DynamicPackManager.writePngAt(
                "assets/conjure/textures/entity/entity_slot_" + slotIndex + ".png",
                argb);
    }

    private EntityAssets() {}
}
